import Extend from 'flarum/common/extenders';
import app from 'flarum/admin/app';
const extensionId = 'zephyrisle-fof-formatting-pro';
const pluginSettings = ['autoaudio', 'netease', 'bilibili'];
const t = key => app.translator.trans("".concat(extensionId, ".").concat(key), {}, true);
const admin = new Extend.Admin();
pluginSettings.forEach(plugin => {
  admin.setting(() => ({
    setting: "".concat(extensionId, ".plugin.").concat(plugin),
    label: t("admin.plugins.".concat(plugin)),
    type: 'boolean'
  }));
});
admin.setting(() => ({
  setting: "".concat(extensionId, ".audio_css"),
  label: t('admin.settings.audio_css'),
  help: t('admin.settings.audio_css_help'),
  placeholder: t('admin.settings.audio_css_placeholder'),
  type: 'textarea'
}));
export default [admin];